1	import { useState } from 'react';
2	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
3	import { listUsers, createUser, addRole, unlockUser } from '../api/analytics';
4	import { formatDate } from '../utils/formatters';
5	
6	export function AdminUsersPage() {
7	  const [page, setPage] = useState(1);
8	  const [showCreate, setShowCreate] = useState(false);
9	  const [form, setForm] = useState({ username: '', password: '', display_name: '', email: '' });
10	  const [roleForm, setRoleForm] = useState({ userId: '', roleName: '' });
11	  const queryClient = useQueryClient();
12	
13	  const { data } = useQuery({
14	    queryKey: ['adminUsers', page],
15	    queryFn: () => listUsers(page).then((r) => r.data),
16	  });
17	
18	  const createMutation = useMutation({
19	    mutationFn: () => createUser(form),
20	    onSuccess: () => {
21	      queryClient.invalidateQueries({ queryKey: ['adminUsers'] });
22	      setShowCreate(false);
23	      setForm({ username: '', password: '', display_name: '', email: '' });
24	    },
25	  });
26	
27	  const addRoleMutation = useMutation({
28	    mutationFn: () => addRole(roleForm.userId, roleForm.roleName),
29	    onSuccess: () => {
30	      queryClient.invalidateQueries({ queryKey: ['adminUsers'] });
31	      setRoleForm({ userId: '', roleName: '' });
32	    },
33	  });
34	
35	  const unlockMutation = useMutation({
36	    mutationFn: unlockUser,
37	    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['adminUsers'] }),
38	  });
39	
40	  return (
41	    <div>
42	      <div className="flex justify-between items-center mb-6">
43	        <h1 className="text-2xl font-bold">User Management</h1>
44	        <button onClick={() => setShowCreate(!showCreate)} className="px-4 py-2 bg-primary-600 text-white rounded text-sm">
45	          {showCreate ? 'Cancel' : 'Create User'}
46	        </button>
47	      </div>
48	
49	      {showCreate && (
50	        <div className="bg-white p-6 rounded-lg shadow-sm border mb-6">
51	          <div className="grid grid-cols-2 gap-4">
52	            <input type="text" placeholder="Username" value={form.username}
53	              onChange={(e) => setForm({ ...form, username: e.target.value })}
54	              className="px-3 py-2 border rounded" />
55	            <input type="password" placeholder="Password (min 8 chars)" value={form.password}
56	              onChange={(e) => setForm({ ...form, password: e.target.value })}
57	              className="px-3 py-2 border rounded" />
58	            <input type="text" placeholder="Display Name" value={form.display_name}
59	              onChange={(e) => setForm({ ...form, display_name: e.target.value })}
60	              className="px-3 py-2 border rounded" />
61	            <input type="email" placeholder="Email (optional)" value={form.email}
62	              onChange={(e) => setForm({ ...form, email: e.target.value })}
63	              className="px-3 py-2 border rounded" />
64	          </div>
65	          <button onClick={() => createMutation.mutate()} className="mt-4 px-4 py-2 bg-primary-600 text-white rounded text-sm">
66	            Create
67	          </button>
68	        </div>
69	      )}
70	
71	      <div className="bg-white rounded-lg shadow-sm border overflow-hidden">
72	        <table className="min-w-full divide-y divide-gray-200">
73	          <thead className="bg-gray-50">
74	            <tr>
75	              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Username</th>
76	              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Display Name</th>
77	              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
78	              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Created</th>
79	              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
80	            </tr>
81	          </thead>
82	          <tbody className="divide-y divide-gray-200">
83	            {data?.data?.map((user) => (
84	              <tr key={user.id}>
85	                <td className="px-4 py-3 text-sm font-medium">{user.username}</td>
86	                <td className="px-4 py-3 text-sm">{user.display_name}</td>
87	                <td className="px-4 py-3 text-sm">
88	                  {user.is_locked ? (
89	                    <span className="text-red-600 font-medium">Locked</span>
90	                  ) : (
91	                    <span className="text-green-600">Active</span>
92	                  )}
93	                </td>
94	                <td className="px-4 py-3 text-sm text-gray-500">{formatDate(user.created_at)}</td>
95	                <td className="px-4 py-3 text-sm">
96	                  <div className="flex gap-2">
97	                    {user.is_locked && (
98	                      <button onClick={() => unlockMutation.mutate(user.id)} className="text-xs text-primary-600 hover:underline">
99	                        Unlock
100	                      </button>
101	                    )}
102	                    <select
103	                      value=""
104	                      onChange={(e) => {
105	                        if (e.target.value) {
106	                          setRoleForm({ userId: user.id, roleName: e.target.value });
107	                          addRoleMutation.mutate();
108	                        }
109	                      }}
110	                      className="text-xs border rounded px-1"
111	                    >
112	                      <option value="">Add role...</option>
113	                      <option value="buyer">Buyer</option>
114	                      <option value="seller">Seller</option>
115	                      <option value="administrator">Admin</option>
116	                      <option value="compliance_analyst">Compliance</option>
117	                    </select>
118	                  </div>
119	                </td>
120	              </tr>
121	            ))}
122	          </tbody>
123	        </table>
124	      </div>
125	    </div>
126	  );
127	}
