1	import api from './client';
2	import type {
3	  ABTest,
4	  ABTestAssignment,
5	  ABTestResult,
6	  AnomalyEvent,
7	  ContentPerformance,
8	  FunnelResponse,
9	  IPRule,
10	  PaginatedResponse,
11	  RetentionCohort,
12	  User,
13	} from '../types';
14	
15	// Analytics
16	export const getFunnel = (days = 7) =>
17	  api.get<FunnelResponse>('/analytics/funnel', { params: { days } });
18	
19	export const getRetention = (days = 30) =>
20	  api.get<RetentionCohort[]>('/analytics/retention', { params: { days } });
21	
22	export const getContentPerformance = (limit = 20) =>
23	  api.get<ContentPerformance[]>('/analytics/content-performance', { params: { limit } });
24	
25	// A/B Tests
26	export const listABTests = () => api.get<ABTest[]>('/ab-tests');
27	
28	export const getABTest = (id: string) =>
29	  api.get<{ test: ABTest; results: ABTestResult[] }>(`/ab-tests/${id}`);
30	
31	export const createABTest = (data: {
32	  name: string;
33	  description: string;
34	  traffic_pct: number;
35	  start_date: string;
36	  end_date: string;
37	  control_variant: string;
38	  test_variant: string;
39	  rollback_threshold_pct: number;
40	}) => api.post<ABTest>('/ab-tests', data);
41	
42	export const rollbackABTest = (id: string) => api.post(`/ab-tests/${id}/rollback`);
43	
44	export const getAssignments = () => api.get<ABTestAssignment[]>('/ab-tests/assignments');
45	
46	// Admin
47	export const listIPRules = () => api.get<IPRule[]>('/admin/ip-rules');
48	
49	export const createIPRule = (cidr: string, action: string) =>
50	  api.post<IPRule>('/admin/ip-rules', { cidr, action });
51	
52	export const deleteIPRule = (id: string) => api.delete(`/admin/ip-rules/${id}`);
53	
54	export const listAnomalies = (page = 1, pageSize = 20, acknowledged?: boolean) =>
55	  api.get<PaginatedResponse<AnomalyEvent>>('/admin/anomalies', {
56	    params: { page, page_size: pageSize, acknowledged: acknowledged?.toString() },
57	  });
58	
59	export const acknowledgeAnomaly = (id: string) => api.patch(`/admin/anomalies/${id}/acknowledge`);
60	
61	export const getMetrics = () => api.get('/admin/metrics');
62	
63	// Users
64	export const listUsers = (page = 1, pageSize = 20) =>
65	  api.get<PaginatedResponse<User>>('/users', { params: { page, page_size: pageSize } });
66	
