72	
73	export const removeRole = (userId: string, roleId: string) =>
74	  api.delete(`/users/${userId}/roles/${roleId}`);
75	
76	export const unlockUser = (userId: string) => api.post(`/users/${userId}/unlock`);
77	
78	// Dashboard
