1	import { useQuery } from '@tanstack/react-query';
2	import { useAuthStore } from '../store/authStore';
3	import { useNotificationStore } from '../store/notificationStore';
4	import { getDashboard } from '../api/analytics';
5	import { listCollectibles } from '../api/collectibles';
6	import { formatCents } from '../utils/formatters';
7	import { Link } from 'react-router-dom';
8	
9	export function DashboardPage() {
10	  const { user, roles } = useAuthStore();
11	  const { unreadCount } = useNotificationStore();
12	
13	  const { data: dashboard } = useQuery({
14	    queryKey: ['dashboard'],
15	    queryFn: () => getDashboard().then((r) => r.data),
16	  });
17	
18	  const { data: ownedItems } = useQuery({
19	    queryKey: ['ownedCollectibles'],
20	    queryFn: () => listCollectibles(1, 6, 'published').then((r) => r.data),
21	  });
22	
23	  return (
24	    <div>
25	      <h1 className="text-xl md:text-2xl lg:text-3xl font-bold mb-4 md:mb-6">
26	        Welcome back, {user?.display_name}
27	      </h1>
28	
29	      {/* Stats cards — 1 col on narrow tablet, 3 cols on wider screens */}
30	      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 mb-6 md:mb-8">
31	        <div className="bg-white p-4 md:p-6 rounded-lg shadow-sm border">
32	          <h3 className="text-sm font-medium text-gray-500">Open Orders</h3>
33	          <p className="text-2xl md:text-3xl font-bold text-primary-700 mt-1">{dashboard?.open_orders ?? 0}</p>
34	          <Link to="/orders" className="text-sm text-primary-600 hover:underline mt-2 block">
35	            View orders
36	          </Link>
37	        </div>
38	        <div className="bg-white p-4 md:p-6 rounded-lg shadow-sm border">
39	          <h3 className="text-sm font-medium text-gray-500">Unread Notifications</h3>
40	          <p className="text-2xl md:text-3xl font-bold text-primary-700 mt-1">{unreadCount}</p>
41	          <Link to="/notifications" className="text-sm text-primary-600 hover:underline mt-2 block">
42	            View notifications
43	          </Link>
44	        </div>
45	        <div className="bg-white p-4 md:p-6 rounded-lg shadow-sm border sm:col-span-2 lg:col-span-1">
46	          <h3 className="text-sm font-medium text-gray-500">Roles</h3>
47	          <div className="flex flex-wrap gap-1 mt-2">
48	            {roles.map((role) => (
49	              <span key={role} className="px-2 py-1 bg-primary-50 text-primary-700 text-xs rounded-full font-medium">
50	                {role}
51	              </span>
52	            ))}
53	          </div>
54	        </div>
55	      </div>
56	
57	      {/* Recent collectibles — responsive grid */}
58	      <div>
59	        <div className="flex justify-between items-center mb-4">
60	          <h2 className="text-base md:text-lg font-semibold">Recent Collectibles</h2>
61	          <Link to="/catalog" className="text-sm text-primary-600 hover:underline">View all</Link>
62	        </div>
63	        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
64	          {ownedItems?.data?.map((item) => (
65	            <Link
66	              key={item.id}
67	              to={`/catalog/${item.id}`}
68	              className="bg-white p-4 rounded-lg shadow-sm border hover:shadow-md transition-shadow"
69	            >
70	              {item.image_url && (
71	                <img src={item.image_url} alt={item.title} className="w-full h-36 md:h-40 object-cover rounded mb-3" />
72	              )}
73	              <h3 className="font-medium text-gray-900">{item.title}</h3>
74	              <p className="text-lg font-bold text-primary-700 mt-1">
75	                {formatCents(item.price_cents, item.currency)}
76	              </p>
77	            </Link>
78	          ))}
79	          {(!ownedItems?.data || ownedItems.data.length === 0) && (
80	            <p className="text-gray-500 col-span-full">No collectibles available yet.</p>
81	          )}
82	        </div>
83	      </div>
84	    </div>
85	  );
86	}
