1	import { useState } from 'react';
2	import { useQuery } from '@tanstack/react-query';
3	import { Link } from 'react-router-dom';
4	import { listCollectibles } from '../api/collectibles';
5	import { formatCents } from '../utils/formatters';
6	
7	export function CatalogPage() {
8	  const [page, setPage] = useState(1);
9	
10	  const { data, isLoading } = useQuery({
11	    queryKey: ['collectibles', page],
12	    queryFn: () => listCollectibles(page).then((r) => r.data),
13	  });
14	
15	  return (
16	    <div>
17	      <h1 className="text-xl md:text-2xl font-bold mb-4 md:mb-6">Catalog</h1>
18	
19	      {isLoading ? (
20	        <p className="text-gray-500">Loading...</p>
21	      ) : (
22	        <>
23	          {/* Responsive grid: 1 col tablet-portrait, 2 cols tablet-landscape, 3-4 cols desktop */}
24	          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-5">
25	            {data?.data?.map((item) => (
26	              <Link
27	                key={item.id}
28	                to={`/catalog/${item.id}`}
29	                className="bg-white p-3 md:p-4 rounded-lg shadow-sm border hover:shadow-md transition-shadow"
30	              >
31	                {item.image_url ? (
32	                  <img src={item.image_url} alt={item.title} className="w-full h-40 md:h-48 object-cover rounded mb-3" />
33	                ) : (
34	                  <div className="w-full h-40 md:h-48 bg-gray-100 rounded mb-3 flex items-center justify-center text-gray-400">
35	                    No image
36	                  </div>
37	                )}
38	                <h3 className="font-medium text-gray-900 truncate">{item.title}</h3>
39	                <p className="text-sm text-gray-500 mt-1 line-clamp-2">{item.description}</p>
40	                <div className="flex justify-between items-center mt-3">
41	                  <p className="text-base md:text-lg font-bold text-primary-700">
42	                    {formatCents(item.price_cents, item.currency)}
43	                  </p>
44	                  <span className="text-xs text-gray-400">{item.view_count} views</span>
45	                </div>
46	              </Link>
47	            ))}
48	          </div>
49	
50	          {data && data.total_pages > 1 && (
51	            <div className="flex justify-center items-center gap-2 mt-6">
52	              <button
53	                onClick={() => setPage((p) => Math.max(1, p - 1))}
54	                disabled={page <= 1}
55	                className="px-3 md:px-4 py-2 bg-white border rounded text-sm disabled:opacity-50"
56	              >
57	                Previous
58	              </button>
59	              <span className="px-3 md:px-4 py-2 text-sm text-gray-600">
60	                Page {page} of {data.total_pages}
61	              </span>
62	              <button
63	                onClick={() => setPage((p) => p + 1)}
64	                disabled={page >= data.total_pages}
65	                className="px-3 md:px-4 py-2 bg-white border rounded text-sm disabled:opacity-50"
66	              >
67	                Next
68	              </button>
69	            </div>
70	          )}
71	        </>
72	      )}
73	    </div>
74	  );
75	}
