14	type OrderHandler struct {
15		orderService *service.OrderService
16	}
17	
18	func NewOrderHandler(os *service.OrderService) *OrderHandler {
19		return &OrderHandler{orderService: os}
20	}
21	
22	func (h *OrderHandler) Create(c echo.Context) error {
23		var req dto.CreateOrderRequest
24		if err := bindAndValidate(c, &req); err != nil {
25			return err
26		}
27	
28		idempotencyKey := c.Request().Header.Get("Idempotency-Key")
29		if idempotencyKey == "" {
30			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "Idempotency-Key header is required")
31		}
32	
33		buyerID, err := uuid.Parse(middleware.GetUserID(c))
34		if err != nil {
35			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
36		}
37	
38		order, err := h.orderService.Create(c.Request().Context(), req, buyerID, idempotencyKey)
39		if err != nil {
40			return mapError(c, err)
41		}
42		return c.JSON(http.StatusCreated, order)
43	}
44	
45	func (h *OrderHandler) Get(c echo.Context) error {
46		id, err := uuid.Parse(c.Param("id"))
47		if err != nil {
48			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
49		}
50	
51		order, err := h.orderService.GetByID(c.Request().Context(), id)
52		if err != nil {
53			return mapError(c, err)
54		}
55		return c.JSON(http.StatusOK, order)
56	}
57	
58	func (h *OrderHandler) List(c echo.Context) error {
59		userID, err := uuid.Parse(middleware.GetUserID(c))
60		if err != nil {
61			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
62		}
63	
64		page, pageSize := pagination(c)
65		role := c.QueryParam("role")
66	
67		var orders []model.Order
68		var total int
69	
70		if role == "seller" {
71			orders, total, err = h.orderService.ListBySeller(c.Request().Context(), userID, page, pageSize)
72		} else {
73			orders, total, err = h.orderService.ListByBuyer(c.Request().Context(), userID, page, pageSize)
74		}
75		if err != nil {
76			return mapError(c, err)
77		}
78		return paginatedResponse(c, orders, page, pageSize, total)
79	}
80	
81	func (h *OrderHandler) Confirm(c echo.Context) error {
82		return h.transition(c, model.OrderStatusConfirmed)
83	}
84	
85	func (h *OrderHandler) Process(c echo.Context) error {
86		return h.transition(c, model.OrderStatusProcessing)
87	}
88	
89	func (h *OrderHandler) Complete(c echo.Context) error {
90		return h.transition(c, model.OrderStatusCompleted)
91	}
92	
93	func (h *OrderHandler) Cancel(c echo.Context) error {
94		id, err := uuid.Parse(c.Param("id"))
95		if err != nil {
96			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
97		}
98	
99		var req dto.CancelOrderRequest
100		if err := bindAndValidate(c, &req); err != nil {
101			return err
102		}
103	
104		actorID, err := uuid.Parse(middleware.GetUserID(c))
105		if err != nil {
106			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
107		}
108	
109		order, err := h.orderService.TransitionStatus(c.Request().Context(), id, model.OrderStatusCancelled, actorID, req.Reason)
110		if err != nil {
111			return mapError(c, err)
112		}
113		return c.JSON(http.StatusOK, order)
114	}
115	
116	func (h *OrderHandler) UpdateFulfillment(c echo.Context) error {
117		id, err := uuid.Parse(c.Param("id"))
118		if err != nil {
119			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
120		}
121	
122		var req dto.UpdateFulfillmentRequest
123		if err := bindAndValidate(c, &req); err != nil {
124			return err
125		}
126	
127		if err := h.orderService.UpdateFulfillment(c.Request().Context(), id, req); err != nil {
128			return mapError(c, err)
129		}
130		return c.JSON(http.StatusOK, map[string]string{"status": "ok"})
131	}
132	
133	func (h *OrderHandler) transition(c echo.Context, status model.OrderStatus) error {
134		id, err := uuid.Parse(c.Param("id"))
135		if err != nil {
136			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
137		}
138	
139		actorID, err := uuid.Parse(middleware.GetUserID(c))
140		if err != nil {
141			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
142		}
143	
144		order, err := h.orderService.TransitionStatus(c.Request().Context(), id, status, actorID, "")
145		if err != nil {
146			return mapError(c, err)
147		}
148		return c.JSON(http.StatusOK, order)
149	}
