1	import { useState } from 'react';
2	import { useNavigate, useParams } from 'react-router-dom';
3	import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
4	import { createCollectible, getCollectible, updateCollectible } from '../api/collectibles';
5	
6	export function CollectibleFormPage() {
7	  const { id } = useParams<{ id: string }>();
8	  const isEdit = !!id;
9	  const navigate = useNavigate();
10	  const queryClient = useQueryClient();
11	
12	  const [form, setForm] = useState({
13	    title: '',
14	    description: '',
15	    price_cents: 0,
16	    currency: 'USD',
17	    contract_address: '',
18	    chain_id: 0,
19	    token_id: '',
20	    metadata_uri: '',
21	    image_url: '',
22	  });
23	  const [error, setError] = useState('');
24	
25	  useQuery({
26	    queryKey: ['collectible', id],
27	    queryFn: () => getCollectible(id!).then((r) => r.data),
28	    enabled: isEdit,
29	    onSuccess: (data: any) => {
30	      const c = data.collectible;
31	      setForm({
32	        title: c.title,
33	        description: c.description,
34	        price_cents: c.price_cents,
35	        currency: c.currency,
36	        contract_address: c.contract_address || '',
37	        chain_id: c.chain_id || 0,
38	        token_id: c.token_id || '',
39	        metadata_uri: c.metadata_uri || '',
40	        image_url: c.image_url || '',
41	      });
42	    },
43	  } as any);
44	
45	  const createMutation = useMutation({
46	    mutationFn: () => createCollectible({
47	      ...form,
48	      price_cents: Number(form.price_cents),
49	      chain_id: form.chain_id || undefined,
50	    }),
51	    onSuccess: (res) => {
52	      queryClient.invalidateQueries({ queryKey: ['collectibles'] });
53	      navigate(`/catalog/${res.data.id}`);
54	    },
55	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
56	  });
57	
58	  const updateMutation = useMutation({
59	    mutationFn: () => updateCollectible(id!, {
60	      title: form.title,
61	      description: form.description,
62	      price_cents: Number(form.price_cents),
63	      image_url: form.image_url,
64	      metadata_uri: form.metadata_uri,
65	    }),
66	    onSuccess: () => {
67	      queryClient.invalidateQueries({ queryKey: ['collectible', id] });
68	      navigate(`/catalog/${id}`);
69	    },
70	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
71	  });
72	
73	  const handleSubmit = (e: React.FormEvent) => {
74	    e.preventDefault();
75	    if (isEdit) updateMutation.mutate();
76	    else createMutation.mutate();
77	  };
78	
79	  return (
80	    <div className="max-w-2xl mx-auto">
81	      <h1 className="text-2xl font-bold mb-6">{isEdit ? 'Edit Listing' : 'Create Listing'}</h1>
82	
83	      <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-sm border p-6 space-y-4">
84	        <div>
85	          <label className="block text-sm font-medium text-gray-700 mb-1">Title *</label>
86	          <input type="text" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })}
87	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required maxLength={300} />
88	        </div>
89	        <div>
90	          <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
91	          <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })}
92	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" rows={4} maxLength={5000} />
93	        </div>
94	        <div className="grid grid-cols-2 gap-4">
95	          <div>
96	            <label className="block text-sm font-medium text-gray-700 mb-1">Price (cents) *</label>
97	            <input type="number" value={form.price_cents} onChange={(e) => setForm({ ...form, price_cents: Number(e.target.value) })}
98	              className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required min={1} />
99	          </div>
100	          <div>
101	            <label className="block text-sm font-medium text-gray-700 mb-1">Currency</label>
102	            <input type="text" value={form.currency} onChange={(e) => setForm({ ...form, currency: e.target.value })}
103	              className="w-full px-3 py-2 border rounded" maxLength={3} />
104	          </div>
105	        </div>
106	        <div>
107	          <label className="block text-sm font-medium text-gray-700 mb-1">Image URL</label>
108	          <input type="url" value={form.image_url} onChange={(e) => setForm({ ...form, image_url: e.target.value })}
109	            className="w-full px-3 py-2 border rounded" />
110	        </div>
111	
112	        {!isEdit && (
113	          <>
114	            <div className="grid grid-cols-2 gap-4">
115	              <div>
116	                <label className="block text-sm font-medium text-gray-700 mb-1">Contract Address</label>
117	                <input type="text" value={form.contract_address} onChange={(e) => setForm({ ...form, contract_address: e.target.value })}
118	                  className="w-full px-3 py-2 border rounded font-mono text-sm" maxLength={42} />
119	              </div>
120	              <div>
121	                <label className="block text-sm font-medium text-gray-700 mb-1">Chain ID</label>
122	                <input type="number" value={form.chain_id || ''} onChange={(e) => setForm({ ...form, chain_id: Number(e.target.value) })}
123	                  className="w-full px-3 py-2 border rounded" />
124	              </div>
125	            </div>
126	            <div>
127	              <label className="block text-sm font-medium text-gray-700 mb-1">Token ID</label>
128	              <input type="text" value={form.token_id} onChange={(e) => setForm({ ...form, token_id: e.target.value })}
129	                className="w-full px-3 py-2 border rounded font-mono text-sm" maxLength={78} />
130	            </div>
131	            <div>
132	              <label className="block text-sm font-medium text-gray-700 mb-1">Metadata URI</label>
133	              <input type="url" value={form.metadata_uri} onChange={(e) => setForm({ ...form, metadata_uri: e.target.value })}
134	                className="w-full px-3 py-2 border rounded" />
135	            </div>
136	          </>
137	        )}
138	
139	        {error && <div className="text-sm text-red-600 bg-red-50 p-2 rounded">{error}</div>}
140	
141	        <div className="flex gap-2">
142	          <button type="submit" className="px-6 py-2 bg-primary-600 text-white rounded hover:bg-primary-700">
143	            {isEdit ? 'Update' : 'Create Listing'}
144	          </button>
145	          <button type="button" onClick={() => navigate(-1)} className="px-6 py-2 bg-gray-100 rounded">Cancel</button>
146	        </div>
147	      </form>
148	    </div>
149	  );
150	}
