1	import api from './client';
2	import type { Collectible, CollectibleTxHistory, PaginatedResponse } from '../types';
3	
4	export const listCollectibles = (page = 1, pageSize = 20, status = 'published') =>
5	  api.get<PaginatedResponse<Collectible>>('/collectibles', { params: { page, page_size: pageSize, status } });
6	
7	export const getCollectible = (id: string) =>
8	  api.get<{ collectible: Collectible; transaction_history: CollectibleTxHistory[] }>(`/collectibles/${id}`);
9	
10	export const createCollectible = (data: {
11	  title: string;
12	  description: string;
13	  price_cents: number;
14	  currency?: string;
15	  contract_address?: string;
16	  chain_id?: number;
17	  token_id?: string;
18	  metadata_uri?: string;
19	  image_url?: string;
20	}) => api.post<Collectible>('/collectibles', data);
21	
22	export const updateCollectible = (id: string, data: Partial<Collectible>) =>
23	  api.patch<Collectible>(`/collectibles/${id}`, data);
24	
25	export const hideCollectible = (id: string, reason: string) =>
26	  api.patch(`/collectibles/${id}/hide`, { reason });
27	
28	export const publishCollectible = (id: string) =>
29	  api.patch(`/collectibles/${id}/publish`);
