1	import { useParams, Link } from 'react-router-dom';
2	import { useState, useRef, useEffect } from 'react';
3	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
4	import { listMessages, sendMessage } from '../api/messages';
5	import { useAuthStore } from '../store/authStore';
6	import { detectPII } from '../utils/piiDetector';
7	import { formatRelativeTime } from '../utils/formatters';
8	
9	const MAX_ATTACHMENT_SIZE = 10 * 1024 * 1024;
10	
11	export function MessagesPage() {
12	  const { id: orderId } = useParams<{ id: string }>();
13	  const { user } = useAuthStore();
14	  const queryClient = useQueryClient();
15	  const [body, setBody] = useState('');
16	  const [attachment, setAttachment] = useState<File | null>(null);
17	  const [piiWarning, setPiiWarning] = useState('');
18	  const [fileError, setFileError] = useState('');
19	  const messagesEndRef = useRef<HTMLDivElement>(null);
20	
21	  const { data } = useQuery({
22	    queryKey: ['messages', orderId],
23	    queryFn: () => listMessages(orderId!, 1, 100).then((r) => r.data),
24	    enabled: !!orderId,
25	    refetchInterval: 10000,
26	  });
27	
28	  const mutation = useMutation({
29	    mutationFn: () => sendMessage(orderId!, body, attachment || undefined),
30	    onSuccess: () => {
31	      setBody('');
32	      setAttachment(null);
33	      setPiiWarning('');
34	      queryClient.invalidateQueries({ queryKey: ['messages', orderId] });
35	    },
36	  });
37	
38	  useEffect(() => {
39	    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
40	  }, [data]);
41	
42	  const handleSend = () => {
43	    const piiResult = detectPII(body);
44	    if (piiResult.detected) {
45	      setPiiWarning(`Message contains sensitive content (${piiResult.types.join(', ')}). Please remove it before sending.`);
46	      return;
47	    }
48	    setPiiWarning('');
49	    mutation.mutate();
50	  };
51	
52	  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
53	    const file = e.target.files?.[0];
54	    setFileError('');
55	    if (file) {
56	      if (file.size > MAX_ATTACHMENT_SIZE) {
57	        setFileError('Attachment exceeds 10MB limit.');
58	        setAttachment(null);
59	        return;
60	      }
61	      setAttachment(file);
62	
63	      // Check text files for PII
64	      if (file.type.startsWith('text/') || file.name.endsWith('.csv') || file.name.endsWith('.txt')) {
65	        const reader = new FileReader();
66	        reader.onload = (ev) => {
67	          const content = ev.target?.result as string;
68	          const piiResult = detectPII(content);
69	          if (piiResult.detected) {
70	            setFileError(`Attachment contains sensitive content (${piiResult.types.join(', ')}). Remove PII before sending.`);
71	            setAttachment(null);
72	          }
73	        };
74	        reader.readAsText(file);
75	      }
76	    }
77	  };
78	
79	  return (
80	    <div className="max-w-3xl mx-auto">
81	      <Link to={`/orders/${orderId}`} className="text-sm text-primary-600 hover:underline mb-4 block">
82	        Back to Order
83	      </Link>
84	
85	      <div className="bg-white rounded-lg shadow-sm border flex flex-col h-[500px] md:h-[600px] lg:h-[700px]">
86	        <div className="p-4 border-b">
87	          <h2 className="font-semibold">Messages - Order #{orderId?.slice(0, 8)}</h2>
88	        </div>
89	
90	        <div className="flex-1 overflow-y-auto p-4 space-y-3">
91	          {data?.data?.map((msg) => {
92	            const isMe = msg.sender_id === user?.id;
93	            return (
94	              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
95	                <div className={`max-w-[70%] p-3 rounded-lg ${isMe ? 'bg-primary-100 text-primary-900' : 'bg-gray-100'}`}>
96	                  <p className="text-sm">{msg.body}</p>
97	                  {msg.attachment_path && (
98	                    <p className="text-xs mt-1 text-gray-500">
99	                      Attachment ({msg.attachment_mime}, {Math.round((msg.attachment_size || 0) / 1024)}KB)
100	                    </p>
101	                  )}
102	                  <p className="text-xs text-gray-400 mt-1">{formatRelativeTime(msg.created_at)}</p>
103	                </div>
104	              </div>
105	            );
106	          })}
107	          <div ref={messagesEndRef} />
108	        </div>
109	
110	        <div className="p-4 border-t">
111	          {piiWarning && (
112	            <div className="text-sm text-red-600 bg-red-50 p-2 rounded mb-2">{piiWarning}</div>
113	          )}
114	          {fileError && (
115	            <div className="text-sm text-red-600 bg-red-50 p-2 rounded mb-2">{fileError}</div>
116	          )}
117	          <div className="flex gap-2">
118	            <input
119	              type="text"
120	              value={body}
121	              onChange={(e) => { setBody(e.target.value); setPiiWarning(''); }}
122	              placeholder="Type a message..."
123	              className="flex-1 px-3 py-2 border rounded focus:outline-none focus:ring-2 focus:ring-primary-500"
124	              onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && handleSend()}
125	            />
126	            <label className="px-3 py-2 bg-gray-100 rounded cursor-pointer text-sm hover:bg-gray-200">
127	              Attach
128	              <input type="file" className="hidden" onChange={handleFileChange} />
129	            </label>
130	            <button
131	              onClick={handleSend}
132	              disabled={!body.trim() || mutation.isPending}
133	              className="px-4 py-2 bg-primary-600 text-white rounded text-sm hover:bg-primary-700 disabled:opacity-50"
134	            >
135	              Send
136	            </button>
137	          </div>
138	          {attachment && (
139	            <p className="text-xs text-gray-500 mt-1">
140	              Attached: {attachment.name} ({Math.round(attachment.size / 1024)}KB)
141	              <button onClick={() => setAttachment(null)} className="ml-2 text-red-500">Remove</button>
142	            </p>
143	          )}
144	        </div>
145	      </div>
146	    </div>
147	  );
148	}
