14	type OrderService struct {
15		orderStore       *store.OrderStore
16		collectibleStore *store.CollectibleStore
17		notifService     *NotificationService
18	}
19	
20	func NewOrderService(os *store.OrderStore, cs *store.CollectibleStore, ns *NotificationService) *OrderService {
21		return &OrderService{orderStore: os, collectibleStore: cs, notifService: ns}
22	}
23	
24	func (s *OrderService) Create(ctx context.Context, req dto.CreateOrderRequest, buyerID uuid.UUID, idempotencyKey string) (*model.Order, error) {
25		// Check idempotency
26		existing, err := s.orderStore.GetByIdempotencyKey(ctx, idempotencyKey)
27		if err != nil {
28			return nil, fmt.Errorf("check idempotency: %w", err)
29		}
30		if existing != nil {
31			return existing, nil // Return existing order, not an error
32		}
33	
34		// Fetch collectible
35		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
36		if err != nil {
37			return nil, fmt.Errorf("get collectible: %w", err)
38		}
39		if collectible == nil {
40			return nil, dto.ErrNotFound
41		}
42		if collectible.Status != "published" {
43			return nil, dto.ErrNotFound
44		}
45		if collectible.SellerID == buyerID {
46			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
47		}
48	
49		// Begin transaction
50		tx, err := s.orderStore.BeginTx(ctx)
51		if err != nil {
52			return nil, fmt.Errorf("begin tx: %w", err)
53		}
54		defer tx.Rollback(ctx)
55	
56		// Acquire advisory lock on collectible
57		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
58			return nil, fmt.Errorf("acquire lock: %w", err)
59		}
60	
61		// Check for active orders
62		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
63		if err != nil {
64			return nil, fmt.Errorf("check active orders: %w", err)
65		}
66		if hasActive {
67			return nil, dto.ErrOversold
68		}
69	
70		// Create order
71		order := &model.Order{
72			IdempotencyKey:     idempotencyKey,
73			BuyerID:            buyerID,
74			CollectibleID:      req.CollectibleID,
75			SellerID:           collectible.SellerID,
76			Status:             model.OrderStatusPending,
77			PriceSnapshotCents: collectible.PriceCents,
78		}
79	
80		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
81			return nil, fmt.Errorf("create order: %w", err)
82		}
83	
84		// Record state transition
85		transition := &model.OrderStateTransition{
86			OrderID:    order.ID,
87			FromStatus: "",
88			ToStatus:   model.OrderStatusPending,
89			ActorID:    buyerID,
90			Reason:     "order created",
91		}
92		if err := s.orderStore.RecordTransitionInTx(ctx, tx, transition); err != nil {
93			return nil, fmt.Errorf("record transition: %w", err)
94		}
95	
96		if err := tx.Commit(ctx); err != nil {
97			return nil, fmt.Errorf("commit: %w", err)
98		}
99	
100		return order, nil
101	}
102	
103	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
104		order, err := s.orderStore.GetByID(ctx, orderID)
105		if err != nil {
106			return nil, err
107		}
108		if order == nil {
109			return nil, dto.ErrNotFound
110		}
111	
112		if !order.Status.CanTransitionTo(targetStatus) {
113			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
114		}
115	
116		if targetStatus == model.OrderStatusCancelled {
117			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
118				return nil, fmt.Errorf("cancel order: %w", err)
119			}
120		} else {
121			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
122				return nil, fmt.Errorf("update status: %w", err)
123			}
124		}
125	
126		// Record transition
127		transition := &model.OrderStateTransition{
128			OrderID:    orderID,
129			FromStatus: order.Status,
130			ToStatus:   targetStatus,
131			ActorID:    actorID,
132			Reason:     reason,
133		}
134		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
135			return nil, fmt.Errorf("record transition: %w", err)
136		}
137	
138		// Send notification
139		s.sendOrderNotification(ctx, order, targetStatus, reason)
140	
141		order.Status = targetStatus
142		return order, nil
143	}
144	
145	func (s *OrderService) sendOrderNotification(ctx context.Context, order *model.Order, status model.OrderStatus, reason string) {
146		if s.notifService == nil {
147			return
148		}
149	
150		slugMap := map[model.OrderStatus]string{
151			model.OrderStatusConfirmed:  "order_confirmed",
152			model.OrderStatusProcessing: "order_processing",
153			model.OrderStatusCompleted:  "order_completed",
154			model.OrderStatusCancelled:  "order_cancelled",
155		}
156	
157		slug, ok := slugMap[status]
158		if !ok {
159			return
160		}
161	
162		// Notify the buyer
163		params := map[string]string{
164			"OrderID": order.ID.String(),
165			"Reason":  reason,
166		}
167		paramsJSON, _ := json.Marshal(params)
168	
169		go func() {
170			_ = s.notifService.Send(context.Background(), order.BuyerID, slug, paramsJSON)
171		}()
172	}
