143	func maskEmail(email string) string {
144		at := -1
145		for i, c := range email {
146			if c == '@' {
147				at = i
148				break
149			}
150		}
151		if at <= 0 {
152			return "***"
153		}
154		masked := string(email[0])
155		for i := 1; i < at; i++ {
156			masked += "*"
157		}
158		masked += email[at:]
159		return masked
160	}
