19	func NewUserService(userStore *store.UserStore, encryptor *crypto.AESEncryptor) *UserService {
20		return &UserService{userStore: userStore, encryptor: encryptor}
21	}
22	
23	func (s *UserService) Create(ctx context.Context, req dto.CreateUserRequest, createdBy uuid.UUID) (*model.User, error) {
24		existing, err := s.userStore.GetByUsername(ctx, req.Username)
25		if err != nil {
26			return nil, fmt.Errorf("check username: %w", err)
27		}
28		if existing != nil {
29			return nil, dto.ErrConflict
30		}
31	
32		hash, err := crypto.HashPassword(req.Password)
33		if err != nil {
34			return nil, fmt.Errorf("hash password: %w", err)
35		}
36	
37		user := &model.User{
38			Username:     req.Username,
39			PasswordHash: hash,
40			DisplayName:  req.DisplayName,
41			CreatedBy:    &createdBy,
42		}
43	
44		if req.Email != "" {
45			encrypted, err := s.encryptor.Encrypt([]byte(req.Email))
46			if err != nil {
47				return nil, fmt.Errorf("encrypt email: %w", err)
48			}
49			user.EmailEncrypted = encrypted
50			user.EmailHash = s.encryptor.HMACHash([]byte(req.Email))
51		}
52	
53		if err := s.userStore.Create(ctx, user); err != nil {
54			return nil, fmt.Errorf("create user: %w", err)
55		}
56		return user, nil
57	}
