59	func (s *UserService) GetByID(ctx context.Context, id uuid.UUID) (*model.User, error) {
60		user, err := s.userStore.GetByID(ctx, id)
61		if err != nil {
62			return nil, err
63		}
64		if user == nil {
65			return nil, dto.ErrNotFound
66		}
67		return user, nil
68	}
69	
70	func (s *UserService) List(ctx context.Context, page, pageSize int) ([]model.User, int, error) {
71		return s.userStore.List(ctx, page, pageSize)
72	}
73	
74	func (s *UserService) Update(ctx context.Context, id uuid.UUID, req dto.UpdateUserRequest) (*model.User, error) {
75		user, err := s.userStore.GetByID(ctx, id)
76		if err != nil {
77			return nil, err
78		}
79		if user == nil {
80			return nil, dto.ErrNotFound
81		}
82	
83		if req.DisplayName != nil {
84			user.DisplayName = *req.DisplayName
85		}
86		if req.Password != nil {
87			hash, err := crypto.HashPassword(*req.Password)
88			if err != nil {
89				return nil, fmt.Errorf("hash password: %w", err)
90			}
91			user.PasswordHash = hash
92		}
93		if req.Email != nil {
94			encrypted, err := s.encryptor.Encrypt([]byte(*req.Email))
95			if err != nil {
96				return nil, fmt.Errorf("encrypt email: %w", err)
97			}
98			user.EmailEncrypted = encrypted
99			user.EmailHash = s.encryptor.HMACHash([]byte(*req.Email))
100		}
101	
102		if err := s.userStore.Update(ctx, user); err != nil {
103			return nil, fmt.Errorf("update user: %w", err)
104		}
105		return user, nil
106	}
