127	func (s *UserService) UnlockAccount(ctx context.Context, userID uuid.UUID) error {
128		return s.userStore.UnlockAccount(ctx, userID)
129	}
130	
131	func (s *UserService) GetMaskedEmail(ctx context.Context, user *model.User) string {
132		if user.EmailEncrypted == nil {
133			return ""
134		}
135		plaintext, err := s.encryptor.Decrypt(user.EmailEncrypted)
136		if err != nil {
137			return "***"
138		}
139		email := string(plaintext)
140		return maskEmail(email)
141	}
142	
143	func maskEmail(email string) string {
144		at := -1
145		for i, c := range email {
146			if c == '@' {
147				at = i
148				break
149			}
150		}
151		if at <= 0 {
152			return "***"
153		}
154		masked := string(email[0])
155		for i := 1; i < at; i++ {
156			masked += "*"
157		}
158		masked += email[at:]
159		return masked
160	}
