1	import { useState } from 'react';
2	import { useNavigate, useParams } from 'react-router-dom';
3	import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
4	import { createCollectible, getCollectible, updateCollectible } from '../api/collectibles';
5	
6	export function CollectibleFormPage() {
7	  const { id } = useParams<{ id: string }>();
8	  const isEdit = !!id;
9	  const navigate = useNavigate();
10	  const queryClient = useQueryClient();
11	
12	  const [form, setForm] = useState({
13	    title: '',
14	    description: '',
15	    price_cents: 0,
16	    currency: 'USD',
17	    contract_address: '',
18	    metadata_uri: '',
19	    image_url: '',
20	  });
21	  const [error, setError] = useState('');
22	
23	  useQuery({
24	    queryKey: ['collectible', id],
25	    queryFn: () => getCollectible(id!).then((r) => r.data),
26	    enabled: isEdit,
27	    onSuccess: (data: any) => {
28	      const c = data.collectible;
29	      setForm({
30	        title: c.title,
31	        description: c.description,
32	        price_cents: c.price_cents,
33	        currency: c.currency,
34	        contract_address: c.contract_address || '',
35	        metadata_uri: c.metadata_uri || '',
36	        image_url: c.image_url || '',
37	      });
38	    },
39	  } as any);
40	
41	  const createMutation = useMutation({
42	    mutationFn: () => createCollectible({
43	      ...form,
44	      price_cents: Number(form.price_cents),
45	    }),
46	    onSuccess: (res) => {
47	      queryClient.invalidateQueries({ queryKey: ['collectibles'] });
48	      navigate(`/catalog/${res.data.id}`);
49	    },
50	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
51	  });
52	
53	  const updateMutation = useMutation({
54	    mutationFn: () => updateCollectible(id!, {
55	      title: form.title,
56	      description: form.description,
57	      price_cents: Number(form.price_cents),
58	      image_url: form.image_url,
59	      metadata_uri: form.metadata_uri,
60	    }),
61	    onSuccess: () => {
62	      queryClient.invalidateQueries({ queryKey: ['collectible', id] });
63	      navigate(`/catalog/${id}`);
64	    },
65	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
66	  });
67	
68	  const handleSubmit = (e: React.FormEvent) => {
69	    e.preventDefault();
70	    if (isEdit) updateMutation.mutate();
71	    else createMutation.mutate();
72	  };
73	
74	  return (
75	    <div className="max-w-2xl mx-auto">
76	      <h1 className="text-2xl font-bold mb-6">{isEdit ? 'Edit Listing' : 'Create Listing'}</h1>
77	
78	      <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-sm border p-6 space-y-4">
79	        <div>
80	          <label className="block text-sm font-medium text-gray-700 mb-1">Title *</label>
81	          <input type="text" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })}
82	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required maxLength={300} />
83	        </div>
84	        <div>
85	          <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
86	          <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })}
87	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" rows={4} maxLength={5000} />
88	        </div>
89	        <div className="grid grid-cols-2 gap-4">
90	          <div>
91	            <label className="block text-sm font-medium text-gray-700 mb-1">Price (cents) *</label>
92	            <input type="number" value={form.price_cents} onChange={(e) => setForm({ ...form, price_cents: Number(e.target.value) })}
93	              className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required min={1} />
94	          </div>
95	          <div>
96	            <label className="block text-sm font-medium text-gray-700 mb-1">Currency</label>
97	            <input type="text" value={form.currency} onChange={(e) => setForm({ ...form, currency: e.target.value })}
98	              className="w-full px-3 py-2 border rounded" maxLength={3} />
99	          </div>
100	        </div>
101	        <div>
102	          <label className="block text-sm font-medium text-gray-700 mb-1">Image URL</label>
103	          <input type="url" value={form.image_url} onChange={(e) => setForm({ ...form, image_url: e.target.value })}
104	            className="w-full px-3 py-2 border rounded" />
105	        </div>
106	
107	        {!isEdit && (
108	          <>
109	            <div>
110	              <label className="block text-sm font-medium text-gray-700 mb-1">Contract Address</label>
111	              <input type="text" value={form.contract_address} onChange={(e) => setForm({ ...form, contract_address: e.target.value })}
112	                className="w-full px-3 py-2 border rounded font-mono text-sm" maxLength={42} />
113	            </div>
114	            <div>
115	              <label className="block text-sm font-medium text-gray-700 mb-1">Metadata URI</label>
116	              <input type="url" value={form.metadata_uri} onChange={(e) => setForm({ ...form, metadata_uri: e.target.value })}
117	                className="w-full px-3 py-2 border rounded" />
118	            </div>
119	            <p className="text-xs text-gray-400">Token ID and Chain ID are generated automatically.</p>
120	          </>
121	        )}
122	
123	        {error && <div className="text-sm text-red-600 bg-red-50 p-2 rounded">{error}</div>}
124	
125	        <div className="flex gap-2">
126	          <button
127	            type="submit"
128	            disabled={createMutation.isPending || updateMutation.isPending || !form.title || !form.price_cents}
129	            className="px-6 py-2 bg-primary-600 text-white rounded hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
130	          >
131	            {createMutation.isPending || updateMutation.isPending
132	              ? (isEdit ? 'Updating...' : 'Creating...')
133	              : (isEdit ? 'Update' : 'Create Listing')}
134	          </button>
135	          <button type="button" onClick={() => navigate(-1)} className="px-6 py-2 bg-gray-100 rounded hover:bg-gray-200">Cancel</button>
136	        </div>
137	      </form>
138	    </div>
139	  );
140	}
